import java.io.*;

public class BufferedStreamExample {
    public static void main(String[] args) {
        // Writing with buffered writer
        System.out.println("=== Writing with BufferedWriter ===");
        try (BufferedWriter bw = new BufferedWriter(new FileWriter("buffered.txt"))) {
            bw.write("Hello, World!");
            bw.newLine();  // Platform-independent new line
            bw.write("Buffered streams are faster!");
            bw.newLine();
            bw.write("They reduce disk I/O operations.");
            System.out.println("Written 3 lines!");
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Reading with buffered reader
        System.out.println("=== Reading with BufferedReader ===");
        try (BufferedReader br = new BufferedReader(new FileReader("buffered.txt"))) {
            String line;
            int lineNum = 1;
            while ((line = br.readLine()) != null) {
                System.out.println("Line " + lineNum + ": " + line);
                lineNum++;
            }
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Performance comparison
        System.out.println("=== Performance comparison ===");
        long startTime = System.currentTimeMillis();

        // Without buffering (slow)
        try (FileWriter fw = new FileWriter("unbuffered.txt")) {
            for (int i = 0; i < 10000; i++) {
                fw.write("Line " + i + "\n");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        long midTime = System.currentTimeMillis();

        // With buffering (fast)
        try (BufferedWriter bw = new BufferedWriter(new FileWriter("buffered.txt"))) {
            for (int i = 0; i < 10000; i++) {
                bw.write("Line " + i);
                bw.newLine();
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        long endTime = System.currentTimeMillis();
        System.out.println("Unbuffered: " + (midTime - startTime) + "ms");
        System.out.println("Buffered: " + (endTime - midTime) + "ms");

        // Wrapping streams
        System.out.println("=== Wrapping ===");
        // BufferedReader can wrap any Reader
        try (BufferedReader br = new BufferedReader(new FileReader("buffered.txt"))) {
            String firstLine = br.readLine();
            System.out.println("First line: " + firstLine);
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

phase2.brokenCode:
import java.io.*;

public class Test {
    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new FileReader("test.txt"))) {
            // Forgetting to check for null
            String line;
            while (true) {
                line = br.readLine();
                System.out.println(line);  // NullPointerException!
            }
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

phase2.explanation:
readLine() returns null when the end of file is reached. You must check for null!

FIX: Always check for null:
while ((line = br.readLine()) != null) {
    System.out.println(line);
}

Without the check, you'll get a NullPointerException when trying to print null.

This is the most common mistake with BufferedReader!

phase3.solution:
import java.io.*;

public class BufferedStreamPractice {
    public static void main(String[] args) {
        // Write
        try (BufferedWriter bw = new BufferedWriter(new FileWriter("poem.txt"))) {
            bw.write("Roses are red");
            bw.newLine();
            bw.write("Violets are blue");
            bw.newLine();
            bw.write("Java is fun");
            bw.newLine();
            bw.write("And so are you");
            bw.newLine();
            bw.write("Keep coding!");
            bw.newLine();
            System.out.println("Poem written!");
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Read
        try (BufferedReader br = new BufferedReader(new FileReader("poem.txt"))) {
            String line;
            int count = 1;
            System.out.println("Reading poem:");
            while ((line = br.readLine()) != null) {
                System.out.println(count + ": " + line);
                count++;
            }
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }
    }
}
